#!/usr/bin/env python3
"""
Bug #0026: jax.jit produces wrong output vs jax.disable_jit.

Patterns    : [['broadcast', 'cumsum_last_axis'], ['broadcast', 'sigmoid_rescaled_to_tanh'], ['constant', 'neg_abs_identity'], ['layout', 'row_reduce_mul_transpose'], ['layout', 'squeeze_unsqueeze'], ['fusion', 'add_mul_add_chain']]
Dependencies: numpy jax
Run         : python unique_0026.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex("00000040"), dtype=np.float32).reshape([1])
_w1 = np.frombuffer(bytes.fromhex("00000040"), dtype=np.float32).reshape([1])
_w2 = np.frombuffer(bytes.fromhex("0000803f"), dtype=np.float32).reshape([1])
_w3 = np.frombuffer(bytes.fromhex("00004040"), dtype=np.float32).reshape([1])
_w4 = np.frombuffer(bytes.fromhex("00004040"), dtype=np.float32).reshape([1])
_w5 = np.frombuffer(bytes.fromhex("cdcccc3d"), dtype=np.float32).reshape([1])
_w6 = np.frombuffer(bytes.fromhex("0000c03f"), dtype=np.float32).reshape([1])
_w7 = np.frombuffer(bytes.fromhex("cdcc4c3e"), dtype=np.float32).reshape([1])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 32, 256])  # input "model_input"


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_cs_out = jnp.cumsum(x, axis=int(_w0.flat[0]))
    n100_srt_sg = (np.float32(1.0) / (np.float32(1.0) + jnp.exp(-n0_cs_out)))
    n100_srt_mu = n100_srt_sg * _w1
    n100_srt_out = n100_srt_mu - _w2
    n200_nai_ng = -n100_srt_out
    n200_nai_out = jnp.abs(n200_nai_ng)
    n300_rrmt_mean = jnp.mean(n200_nai_out, axis=(-1,), keepdims=True)
    n300_rrmt_sub = n200_nai_out - n300_rrmt_mean
    n300_rrmt_scl = n300_rrmt_sub * n300_rrmt_sub
    n300_rrmt_tp = jnp.transpose(n300_rrmt_scl, [0, 2, 1])
    n300_rrmt_out = jnp.transpose(n300_rrmt_tp, [0, 2, 1])
    n400_su_sq = (lambda _x, _ax: jnp.expand_dims(_x, axis=int(_ax.flat[0])))(n300_rrmt_out, _w3)
    n400_su_out = jnp.squeeze(n400_su_sq)
    n500_ama_x1 = n400_su_out + _w5
    n500_ama_x2 = n500_ama_x1 * _w6
    n500_ama_out = n500_ama_x2 + _w7
    return jnp.asarray(n500_ama_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)

    with jax.disable_jit():
        ref = np.array(model(x_jax), dtype=np.float32).ravel()

    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(ref.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(ref.astype(np.float64)) + 1e-8))
    print(f"expected (jax.disable_jit): {ref[:6]}")
    print(f"actual   (jax.jit)        : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
